    s1h: "1. \u898F\u7D04\u306E\u627F\u8A8D",
    s1: "MyPDFCV \u306B\u30A2\u30AF\u30BB\u30B9\u3057\u4F7F\u7528\u3059\u308B\u3053\u3068\u3067\u3001\u3053\u308C\u3089\u306E\u5229\u7528\u898F\u7D04\u306B\u62D8\u675F\u3055\u308C\u308B\u3053\u3068\u306B\u540C\u610F\u3057\u307E\u3059\u3002\u540C\u610F\u3057\u306A\u3044\u5834\u5408\u306F\u3001\u30B5\u30FC\u30D3\u30B9\u3092\u4F7F\u7528\u3057\u306A\u3044\u3067\u304F\u3060\u3055\u3044\u3002",
    s2h: "2. \u30B5\u30FC\u30D3\u30B9\u306E\u8AAC\u660E",
    s2: "MyPDFCV \u306F\u7121\u6599\u306E\u30AF\u30E9\u30A4\u30A2\u30F3\u30C8\u30B5\u30A4\u30C9\u5C65\u6B74\u66F8\u4F5C\u6210\u30C4\u30FC\u30EB\u3067\u3059\u3002\u3059\u3079\u3066\u306E\u5C65\u6B74\u66F8\u30C7\u30FC\u30BF\u306F\u30D6\u30E9\u30A6\u30B6\u306B\u30ED\u30FC\u30AB\u30EB\u306B\u4FDD\u5B58\u3055\u308C\u307E\u3059\u3002\u5C65\u6B74\u66F8\u30C7\u30FC\u30BF\u306E\u30DB\u30B9\u30C6\u30A3\u30F3\u30B0\u3001\u30B9\u30C8\u30EC\u30FC\u30B8\u3001\u30D0\u30C3\u30AF\u30A2\u30C3\u30D7\u30B5\u30FC\u30D3\u30B9\u306F\u63D0\u4F9B\u3057\u307E\u305B\u3093\u3002\u30B5\u30FC\u30D3\u30B9\u6539\u5584\u306E\u305F\u3081 PostHog \u3092\u901A\u3058\u3066\u533F\u540D\u306E\u5229\u7528\u5206\u6790\u30C7\u30FC\u30BF\u3092\u53CE\u96C6\u3057\u3066\u3044\u307E\u3059\u3002\u30A2\u30CA\u30EA\u30C6\u30A3\u30AF\u30B9\u30C7\u30FC\u30BF\u306B\u306F\u5C65\u6B74\u66F8\u306E\u5185\u5BB9\u3084\u500B\u4EBA\u60C5\u5831\u306F\u542B\u307E\u308C\u307E\u305B\u3093\u3002",
    s3h: "3. AI \u642D\u8F09\u6A5F\u80FD",
