    s4h: "4. \u30C9\u30AD\u30E5\u30E1\u30F3\u30C8\u30A4\u30F3\u30DD\u30FC\u30C8\u6A5F\u80FD",
    s4: "\u30C9\u30AD\u30E5\u30E1\u30F3\u30C8\u30A4\u30F3\u30DD\u30FC\u30C8\u6A5F\u80FD\u306F\u3001PDF \u304A\u3088\u3073 DOCX \u30D5\u30A1\u30A4\u30EB\u3092\u30D6\u30E9\u30A6\u30B6\u5185\u3067\u5B8C\u5168\u306B\u51E6\u7406\u3057\u307E\u3059\u3002\u30A2\u30C3\u30D7\u30ED\u30FC\u30C9\u3055\u308C\u305F\u30D5\u30A1\u30A4\u30EB\u306F\u30C6\u30AD\u30B9\u30C8\u62BD\u51FA\u306E\u305F\u3081\u306B\u30E1\u30E2\u30EA\u306B\u8AAD\u307F\u8FBC\u307E\u308C\u3001\u76F4\u3061\u306B\u7834\u68C4\u3055\u308C\u307E\u3059\u3002\u30C9\u30AD\u30E5\u30E1\u30F3\u30C8\u306E\u30A2\u30C3\u30D7\u30ED\u30FC\u30C9\u3001\u9001\u4FE1\u3001\u4FDD\u5B58\u306F\u884C\u3044\u307E\u305B\u3093\u3002\u30C6\u30AD\u30B9\u30C8\u62BD\u51FA\u306E\u54C1\u8CEA\u306F\u30C9\u30AD\u30E5\u30E1\u30F3\u30C8\u306E\u5F62\u5F0F\u3068\u69CB\u9020\u306B\u3088\u3063\u3066\u7570\u306A\u308A\u307E\u3059\u3002",
    s5h: "5. \u30AA\u30FC\u30D7\u30F3\u30BD\u30FC\u30B9\u30BD\u30D5\u30C8\u30A6\u30A7\u30A2",
    s5: "MyPDFCV \u306F\u30AA\u30FC\u30D7\u30F3\u30BD\u30FC\u30B9\u30BD\u30D5\u30C8\u30A6\u30A7\u30A2\u3067\u69CB\u7BC9\u3055\u308C\u3066\u3044\u307E\u3059\u3002\u4EE5\u4E0B\u306E\u4E3B\u8981\u30E9\u30A4\u30D6\u30E9\u30EA\u304C\u305D\u308C\u305E\u308C\u306E\u30E9\u30A4\u30BB\u30F3\u30B9\u306E\u4E0B\u3067\u4F7F\u7528\u3055\u308C\u3066\u3044\u307E\u3059\uFF1A",
