    s5note: "\u5B8C\u5168\u306A\u30E9\u30A4\u30BB\u30F3\u30B9\u30C6\u30AD\u30B9\u30C8\u306F\u5404\u30E9\u30A4\u30D6\u30E9\u30EA\u306E\u30EA\u30DD\u30B8\u30C8\u30EA\u3067\u5165\u624B\u3067\u304D\u307E\u3059\u3002\u3053\u308C\u3089\u306E\u30E9\u30A4\u30D6\u30E9\u30EA\u306E\u4F7F\u7528\u306F\u3001\u305D\u306E\u4F5C\u6210\u8005\u3084\u30E1\u30F3\u30C6\u30CA\u30FC\u306E\u63A8\u5968\u3092\u610F\u5473\u3059\u308B\u3082\u306E\u3067\u306F\u3042\u308A\u307E\u305B\u3093\u3002",
    s6h: "6. \u4FDD\u8A3C\u306A\u3057",
    s6: "\u3053\u306E\u30B5\u30FC\u30D3\u30B9\u306F\u3001\u660E\u793A\u7684\u307E\u305F\u306F\u6697\u793A\u7684\u3092\u554F\u308F\u305A\u3001\u3044\u304B\u306A\u308B\u7A2E\u985E\u306E\u4FDD\u8A3C\u3082\u306A\u304F\u300C\u73FE\u72B6\u306E\u307E\u307E\u300D\u304A\u3088\u3073\u300C\u5229\u7528\u53EF\u80FD\u306A\u9650\u308A\u300D\u3067\u63D0\u4F9B\u3055\u308C\u307E\u3059\u3002\u30B5\u30FC\u30D3\u30B9\u304C\u4E2D\u65AD\u3055\u308C\u306A\u3044\u3053\u3068\u3001\u30A8\u30E9\u30FC\u304C\u306A\u3044\u3053\u3068\u3001\u30C7\u30FC\u30BF\u304C\u4FDD\u6301\u3055\u308C\u308B\u3053\u3068\u3092\u4FDD\u8A3C\u3057\u307E\u305B\u3093\u3002\u3059\u3079\u3066\u306E\u30C7\u30FC\u30BF\u304C\u30D6\u30E9\u30A6\u30B6\u306E localStorage \u306B\u4FDD\u5B58\u3055\u308C\u308B\u305F\u3081\u3001\u30D6\u30E9\u30A6\u30B6\u30C7\u30FC\u30BF\u3092\u30AF\u30EA\u30A2\u3059\u308B\u3068\u5C65\u6B74\u66F8\u306F\u5B8C\u5168\u306B\u524A\u9664\u3055\u308C\u307E\u3059\u3002",
    s7h: "7. \u8CAC\u4EFB\u306E\u5236\u9650",
    s7: "\u6CD5\u5F8B\u3067\u8A31\u53EF\u3055\u308C\u308B\u6700\u5927\u9650\u306E\u7BC4\u56F2\u306B\u304A\u3044\u3066\u3001\u30B5\u30FC\u30D3\u30B9\u904B\u55B6\u8005\u306F\u3001\u3053\u306E\u30B5\u30FC\u30D3\u30B9\u306E\u4F7F\u7528\u307E\u305F\u306F\u4F7F\u7528\u4E0D\u80FD\u304B\u3089\u751F\u3058\u308B\u9593\u63A5\u7684\u3001\u4ED8\u968F\u7684\u3001\u7279\u5225\u3001\u7D50\u679C\u7684\u3001\u307E\u305F\u306F\u61F2\u7F70\u7684\u640D\u5BB3\u306B\u3064\u3044\u3066\u8CAC\u4EFB\u3092\u8CA0\u3044\u307E\u305B\u3093\u3002\u3053\u308C\u306B\u306F\u30C7\u30FC\u30BF\u306E\u55AA\u5931\u3001\u5C31\u8077\u6A5F\u4F1A\u306E\u55AA\u5931\u3001\u305D\u306E\u4ED6\u306E\u640D\u5931\u304C\u542B\u307E\u308C\u307E\u3059\u3002",
    s8h: "8. \u30E6\u30FC\u30B6\u30FC\u306E\u8CAC\u4EFB",
    s8: "\u5C65\u6B74\u66F8\u306E\u3059\u3079\u3066\u306E\u5185\u5BB9\u306E\u6B63\u78BA\u6027\u3068\u771F\u5B9F\u6027\u306B\u3064\u3044\u3066\u306F\u304A\u5BA2\u69D8\u306E\u8CAC\u4EFB\u3067\u3059\u3002\u8AA4\u89E3\u3092\u62DB\u304F\u3001\u8A50\u6B3A\u7684\u3001\u307E\u305F\u306F\u9055\u6CD5\u306A\u6587\u66F8\u3092\u4F5C\u6210\u3059\u308B\u305F\u3081\u306B\u3053\u306E\u30B5\u30FC\u30D3\u30B9\u3092\u4F7F\u7528\u3057\u306A\u3044\u3053\u3068\u306B\u540C\u610F\u3057\u307E\u3059\u3002",
    s9h: "9. \u6E96\u62E0\u6CD5",
    s9: "\u3053\u306E\u30B5\u30FC\u30D3\u30B9\u306F\u7C73\u56FD\u304B\u3089\u63D0\u4F9B\u3055\u308C\u307E\u3059\u3002\u3053\u308C\u3089\u306E\u898F\u7D04\u304B\u3089\u751F\u3058\u308B\u7D1B\u4E89\u306F\u3001\u6CD5\u306E\u62B5\u89E6\u306B\u95A2\u3059\u308B\u539F\u5247\u306B\u95A2\u308F\u3089\u305A\u3001\u7C73\u56FD\u30AB\u30EA\u30D5\u30A9\u30EB\u30CB\u30A2\u5DDE\u306E\u6CD5\u5F8B\u306B\u6E96\u62E0\u3059\u308B\u3082\u306E\u3068\u3057\u307E\u3059\u3002\u6B27\u5DDE\u9023\u5408\u307E\u305F\u306F\u6B27\u5DDE\u7D4C\u6E08\u9818\u57DF\u306B\u6240\u5728\u3059\u308B\u5834\u5408\u3001\u3053\u308C\u3089\u306E\u898F\u7D04\u306E\u3044\u304B\u306A\u308B\u5185\u5BB9\u3082 GDPR \u307E\u305F\u306F\u305D\u306E\u4ED6\u306E\u9069\u7528\u3055\u308C\u308B\u73FE\u5730\u6CD5\u306B\u57FA\u3065\u304F\u6A29\u5229\u306B\u5F71\u97FF\u3092\u4E0E\u3048\u307E\u305B\u3093\u3002",
    s10h: "10. \u898F\u7D04\u306E\u5909\u66F4",
